import{_ as e,c as a,a as r,o as d}from"./app-U7mDFV7x.js";const n={};function o(i,t){return d(),a("div",null,[...t[0]||(t[0]=[r('<h1 id="appsidebar-component" tabindex="-1"><a class="header-anchor" href="#appsidebar-component"><span>AppSidebar Component</span></a></h1><p>Provides the application sidebar with editing controls, autodetection tools, and page navigation.</p><hr><h2 id="overview" tabindex="-1"><a class="header-anchor" href="#overview"><span>Overview</span></a></h2><p>The <code>AppSidebar</code> component offers:</p><ul><li>Sidebar controls for editing and navigation</li><li>Buttons for selection, drawing, adding, and deleting zones</li><li>Autodetection tools for measures/zones</li><li>Page navigation controls</li></ul><hr><h2 id="layout" tabindex="-1"><a class="header-anchor" href="#layout"><span>Layout</span></a></h2><ul><li><strong>Top</strong>: Mode buttons (select, draw, add zone, delete)</li><li><strong>Middle</strong>: Autodetection tools (e.g., autodetect measures)</li><li><strong>Bottom</strong>: Page navigation (current page, total pages, prev/next)</li></ul><hr><h2 id="props" tabindex="-1"><a class="header-anchor" href="#props"><span>Props</span></a></h2><p><em>None</em></p><hr><h2 id="data" tabindex="-1"><a class="header-anchor" href="#data"><span>Data</span></a></h2><p><em>None</em></p><hr><h2 id="computed-properties" tabindex="-1"><a class="header-anchor" href="#computed-properties"><span>Computed Properties</span></a></h2><table><thead><tr><th>Name</th><th>Description</th></tr></thead><tbody><tr><td>isReady</td><td>Whether the app is ready for user actions</td></tr><tr><td>multiZone</td><td>Whether multi-zone mode is active</td></tr><tr><td>currentPage</td><td>Current page number (1-based)</td></tr><tr><td>maxPage</td><td>Maximum page number</td></tr><tr><td>prevAvailable</td><td>Whether the previous page is available</td></tr><tr><td>nextAvailable</td><td>Whether the next page is available</td></tr><tr><td>workingMode</td><td>Current working mode (e.g., preprocessing, editing)</td></tr><tr><td>mode</td><td>Current sidebar mode (selection, drawing, etc.)</td></tr></tbody></table><hr><h2 id="methods" tabindex="-1"><a class="header-anchor" href="#methods"><span>Methods</span></a></h2><table><thead><tr><th>Name</th><th>Description</th></tr></thead><tbody><tr><td>showPrevPage</td><td>Navigates to the previous page</td></tr><tr><td>showNextPage</td><td>Navigates to the next page</td></tr><tr><td>autoDetect</td><td>Automatically detects zones on the current page</td></tr><tr><td>autoDetectAll</td><td>Automatically detects zones on all pages</td></tr><tr><td>activateMode</td><td>Activates a specific mode (selection, drawing, etc.)</td></tr></tbody></table><hr><h2 id="example" tabindex="-1"><a class="header-anchor" href="#example"><span>Example</span></a></h2><div class="language-vue line-numbers-mode" data-highlighter="prismjs" data-ext="vue"><pre><code><span class="line"><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>AppSidebar</span> <span class="token punctuation">/&gt;</span></span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"></div></div>',24)])])}const p=e(n,[["render",o]]),l=JSON.parse('{"path":"/AppSidebarComponent.html","title":"AppSidebar Component","lang":"en-US","frontmatter":{},"git":{"updatedTime":1747234892000,"contributors":[{"name":"Hizkiel","username":"Hizkiel","email":"hizclick@gmail.com","commits":1,"url":"https://github.com/Hizkiel"}],"changelog":[{"hash":"addcf634062a696867cd389eb76f27f467f4a69a","time":1747234892000,"email":"hizclick@gmail.com","author":"Hizkiel","message":"Correcting the impits based on the pr comments"}]},"filePathRelative":"AppSidebarComponent.md"}');export{p as comp,l as data};
